    /** @return array<string, mixed> */
    public function projectionCurveVisualization(): array
    {
        return $this->shared->chartVisualization(
            key: 'projection_curve',
            type: VisualizationType::Line,
            title: $this->shared->t(en: 'Conditional security-window pressure', it: 'Pressione della finestra di sicurezza condizionale', fr: 'Pression de la fenêtre de sécurité conditionnelle', de: 'Druck des bedingten Sicherheitsfensters', es: 'Presión de la ventana de seguridad condicional', nl: 'Druk van het voorwaardelijke veiligheidsvenster', sv: 'Tryck i det villkorade säkerhetsfönstret', pl: 'Presja warunkowego okna bezpieczeństwa'),
            description: $this->shared->t(en: 'Editorial temporal paths from a common 2026 baseline to conditional scenario deadlines after winter 2027, at end-2030 and at end-2035.', it: 'Percorsi temporali editoriali da una base comune 2026 a scadenze condizionali dopo l’inverno 2027, a fine 2030 e a fine 2035.', fr: 'Trajectoires temporelles éditoriales depuis une base commune en 2026 vers des échéances conditionnelles après l’hiver 2027, fin 2030 et fin 2035.', de: 'Redaktionelle Zeitpfade von einer gemeinsamen Basis 2026 zu bedingten Szenariofristen nach dem Winter 2027, Ende 2030 und Ende 2035.', es: 'Trayectorias temporales editoriales desde una base común de 2026 hasta plazos condicionales después del invierno de 2027, a finales de 2030 y a finales de 2035.', nl: 'Redactionele tijdspaden van een gezamenlijke basis in 2026 naar voorwaardelijke deadlines na de winter van 2027, eind 2030 en eind 2035.', sv: 'Redaktionella tidsbanor från en gemensam bas 2026 till villkorade tidsgränser efter vintern 2027, i slutet av 2030 och i slutet av 2035.', pl: 'Redakcyjne ścieżki czasowe od wspólnej bazy 2026 do warunkowych terminów po zimie 2027, pod koniec 2030 i pod koniec 2035 roku.'),
            reasoning: $this->shared->t(
                en: 'Derived editorial time-window pressure index, not a probability, readiness score or official forecast. For year y and scenario target year t: value = min(100, round(50 + 50 × (y - 2026) / (t - 2026))). After the target year the value remains 100. Target years are 2027 pessimistic, 2030 neutral and 2035 optimistic. The pessimistic exact date is the user-selected post-winter checkpoint of 31 March 2027; no cited source derives that day.',
                it: 'Indice editoriale derivato di pressione della finestra temporale, non una probabilità, un punteggio di prontezza o una previsione ufficiale. Per l’anno y e l’anno target t: valore = min(100, round(50 + 50 × (y - 2026) / (t - 2026))). Dopo l’anno target il valore resta 100. Gli anni target sono 2027 pessimistico, 2030 neutrale e 2035 ottimistico. La data pessimistica esatta è il checkpoint post-inverno del 31 marzo 2027 scelto dall’utente; nessuna fonte citata deriva quel giorno.',
                fr: 'Indice éditorial dérivé de pression de fenêtre temporelle, ni probabilité, ni score de préparation, ni prévision officielle. Pour l’année y et l’année cible t : valeur = min(100, round(50 + 50 × (y - 2026) / (t - 2026))). Après l’année cible, la valeur reste 100. Les années cibles sont 2027 pessimiste, 2030 neutre et 2035 optimiste. La date pessimiste exacte est le jalon d’après-hiver du 31 mars 2027 choisi par l’utilisateur; aucune source citée ne dérive ce jour.',
                de: 'Abgeleiteter redaktioneller Zeitfenster-Druckindex, weder Wahrscheinlichkeit noch Bereitschaftswert oder offizielle Prognose. Für Jahr y und Zieljahr t gilt: Wert = min(100, round(50 + 50 × (y - 2026) / (t - 2026))). Nach dem Zieljahr bleibt der Wert 100. Zieljahre sind 2027 pessimistisch, 2030 neutral und 2035 optimistisch. Das genaue pessimistische Datum ist der vom Nutzer gewählte Zeitpunkt nach dem Winter am 31. März 2027; keine zitierte Quelle leitet diesen Tag ab.',
                es: 'Índice editorial derivado de presión de ventana temporal, no una probabilidad, puntuación de preparación ni previsión oficial. Para el año y y el año objetivo t: valor = min(100, round(50 + 50 × (y - 2026) / (t - 2026))). Tras el año objetivo el valor permanece en 100. Los años son 2027 pesimista, 2030 neutral y 2035 optimista. La fecha pesimista exacta es el hito posterior al invierno del 31 de marzo de 2027 elegido por el usuario; ninguna fuente citada deriva ese día.',
                nl: 'Afgeleide redactionele tijdvensterdrukindex, geen waarschijnlijkheid, paraatheidsscore of officiële voorspelling. Voor jaar y en doeljaar t: waarde = min(100, round(50 + 50 × (y - 2026) / (t - 2026))). Na het doeljaar blijft de waarde 100. Doeljaren zijn 2027 pessimistisch, 2030 neutraal en 2035 optimistisch. De exacte pessimistische datum is het door de gebruiker gekozen ijkpunt na de winter van 31 maart 2027; geen aangehaalde bron leidt die dag af.',
                sv: 'Härlett redaktionellt index för tidsfönstertryck, inte sannolikhet, beredskapspoäng eller officiell prognos. För år y och målår t: värde = min(100, round(50 + 50 × (y - 2026) / (t - 2026))). Efter målåret ligger värdet kvar på 100. Målåren är 2027 pessimistiskt, 2030 neutralt och 2035 optimistiskt. Det exakta pessimistiska datumet är den användarvalda kontrollpunkten efter vintern den 31 mars 2027; ingen citerad källa härleder den dagen.',
                pl: 'Pochodny redakcyjny indeks presji okna czasowego, a nie prawdopodobieństwo, wynik gotowości ani oficjalna prognoza. Dla roku y i roku docelowego t: wartość = min(100, round(50 + 50 × (y - 2026) / (t - 2026))). Po roku docelowym wartość pozostaje 100. Lata docelowe to 2027 pesymistyczny, 2030 neutralny i 2035 optymistyczny. Dokładna data pesymistyczna to wybrany przez użytkownika punkt po zimie 31 marca 2027 roku; żadna cytowana źródłowa ocena nie wyprowadza tego dnia.',
            ),
            labels: ['2026', '2027', '2028', '2029', '2030', '2031', '2032', '2033', '2034', '2035'],
            series: [
                ['name' => 'Pessimistic', 'color' => '#ff2a23', 'values' => [50, 100, 100, 100, 100, 100, 100, 100, 100, 100]],
                ['name' => 'Neutral', 'color' => '#38bdf8', 'values' => [50, 63, 75, 88, 100, 100, 100, 100, 100, 100]],
                ['name' => 'Optimistic', 'color' => '#22c55e', 'values' => [50, 56, 61, 67, 72, 78, 83, 89, 94, 100]],
